create table public.breeds (
  id uuid primary key default gen_random_uuid(),
  species text not null,
  breed_name text not null,
  general_prompt text not null,
  is_mixed_unknown boolean not null default false,
  display_order int not null default 0,
  created_at timestamptz not null default now()
);

grant select on public.breeds to anon, authenticated;
grant all on public.breeds to service_role;

alter table public.breeds enable row level security;

create policy "breeds are publicly readable" on public.breeds
  for select using (true);

